"use client";

import Image from "next/image";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { Suspense, useState } from "react";
import { FirebaseError } from "firebase/app";
import { signInWithEmailAndPassword } from "firebase/auth";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { apiFetch } from "@/lib/api";
import { setAuthSession } from "@/lib/auth";
import { firebaseAuth } from "@/lib/firebase";
import { publicAssetPath } from "@/lib/paths";
import type { User } from "@/lib/types";

export default function LoginPage() {
  return (
    <Suspense fallback={<div className="flex min-h-screen items-center justify-center text-sm text-muted-foreground">Loading login...</div>}>
      <LoginContent />
    </Suspense>
  );
}

function LoginContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function submit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setError("");
    setLoading(true);

    try {
      const credential = await signInWithEmailAndPassword(firebaseAuth, email, password);
      const token = await credential.user.getIdToken();
      const response = await apiFetch<{ user: User }>("/api/auth/me", { token });
      setAuthSession(token, response.user);
      router.replace(searchParams.get("next") ?? (response.user.role === "Advocate" ? "/advocate" : "/dashboard"));
    } catch (err) {
      setError(getLoginErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="grid min-h-screen bg-muted/30 lg:grid-cols-[1fr_460px]">
      <section className="hidden border-r border-border bg-background p-10 lg:flex lg:flex-col lg:justify-between">
        <Link href="/" aria-label="Back to LUMENTIX home">
          <Image src={publicAssetPath("/lumentix-logo.png")} alt="Lumentix" width={300} height={113} priority />
        </Link>
        <div className="max-w-2xl">
          <p className="mb-4 text-sm uppercase text-muted-foreground">Employee access</p>
          <h1 className="text-4xl font-semibold leading-tight">A focused workspace for Lumentix teams and authorized employees.</h1>
        </div>
        <p className="text-sm text-muted-foreground">LUMENTIX SOLUTIONS PRIVATE LIMITED</p>
      </section>
      <section className="flex items-center justify-center p-4">
        <Card className="w-full max-w-md">
          <CardHeader>
            <CardTitle>Sign in</CardTitle>
            <p className="text-sm text-muted-foreground">Use your authorized Lumentix employee account.</p>
          </CardHeader>
          <CardContent>
            <form className="space-y-4" onSubmit={submit}>
              <div className="space-y-2">
                <Label>Email</Label>
                <Input type="email" value={email} onChange={(event) => setEmail(event.target.value)} required />
              </div>
              <div className="space-y-2">
                <Label>Password</Label>
                <Input type="password" value={password} onChange={(event) => setPassword(event.target.value)} required />
              </div>
              {error ? <p className="text-sm text-destructive">{error}</p> : null}
              <Button className="w-full" disabled={loading}>
                {loading ? "Signing in..." : "Sign in"}
              </Button>
            </form>
            <p className="mt-4 text-center text-sm text-muted-foreground">
              <Link className="font-medium text-primary hover:underline" href="/">
                Back to lumentix.in
              </Link>
            </p>
          </CardContent>
        </Card>
      </section>
    </main>
  );
}

function getLoginErrorMessage(error: unknown) {
  if (error instanceof FirebaseError) {
    if (["auth/invalid-credential", "auth/user-not-found", "auth/wrong-password"].includes(error.code)) {
      return "The email or password is incorrect, or this employee account has not been enabled yet.";
    }

    if (error.code === "auth/too-many-requests") {
      return "Too many sign-in attempts. Please wait a few minutes and try again.";
    }

    if (error.code === "auth/operation-not-allowed") {
      return "Employee sign-in is not enabled for this project yet.";
    }
  }

  return error instanceof Error ? error.message : "Sign in failed. Please check your employee account details.";
}
